import React from 'react';

function App() {
  return (
    <div className="min-h-screen bg-[#fdf6ec] text-gray-800 flex flex-col items-center justify-center">
      <img src="/logo.png" alt="MHO Logo" className="w-32 mb-4" />
      <h1 className="text-4xl font-bold mb-2">Mishby Health OS</h1>
      <p className="mb-8">Sarve Santu Niramayah</p>
      <a href="#" className="bg-green-600 text-white px-6 py-2 rounded-full shadow hover:bg-green-700 transition">Open Health Plan Form</a>
    </div>
  );
}

export default App;
